1	// ResumeDriver translates a hybrid_state_v1 into a sequence of DMI register
2	// ops against the RISC-V Debug Module. The orchestration is testable in
3	// isolation by injecting a recording bus.
4	
5	#include "hybrid/abstract_command.hpp"
6	#include "hybrid/program_buffer.hpp"
7	#include "hybrid/resume_driver.hpp"
8	#include "hybrid/state_abi.h"
9	
10	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
11	#include <doctest.h>
12	
13	#include <cstdint>
14	#include <deque>
15	#include <optional>
16	#include <vector>
17	
18	namespace {
19	
20	// DMI register addresses from RISC-V Debug Spec 1.0.
21	constexpr uint8_t kDmcontrol  = 0x10;
22	constexpr uint8_t kDmstatus   = 0x11;
23	constexpr uint8_t kAbstractcs = 0x16;
24	constexpr uint8_t kCommand    = 0x17;
25	constexpr uint8_t kData0      = 0x04;
26	constexpr uint8_t kData1      = 0x05;
27	
28	// CSR numbers from Debug Spec.
29	constexpr uint16_t kCsrDpc = 0x7B1;
30	
31	struct DmiOp
32	{
33	  enum class Kind
34	  {
35	    Write,
36	    Read,
37	  };
38	  Kind kind;
39	  uint8_t reg;
40	  uint32_t value;  // for writes only
41	};
42	
43	struct RecordingBus final : hybrid::DmiBus
44	{
45	  std::vector<DmiOp> ops;
46	
47	  // Test-controlled response values for reads.
48	  uint32_t dmstatus_value = 0;       // bit 9: allhalted, bit 17: allresumeack
49	  uint32_t abstractcs_value = 0;     // fallback when queue is empty
50	  std::deque<uint32_t> abstractcs_queue; // queued reads drain first
51	
52	  void write(uint8_t reg, uint32_t value) override
53	  {
54	    ops.push_back({DmiOp::Kind::Write, reg, value});
55	  }
56	
57	  auto read(uint8_t reg) -> uint32_t override
58	  {
59	    ops.push_back({DmiOp::Kind::Read, reg, 0});
60	    if (reg == kDmstatus) return dmstatus_value;
61	    if (reg == kAbstractcs) {
62	      if (!abstractcs_queue.empty()) {
63	        auto v = abstractcs_queue.front();
64	        abstractcs_queue.pop_front();
65	        return v;
66	      }
67	      return abstractcs_value;
68	    }
69	    return 0;
70	  }
71	};
72	
73	auto rv64_state(uint64_t pc, uint64_t x10) -> hybrid_state_v1
74	{
75	  hybrid_state_v1 s{};
76	  s.magic = HYBRID_STATE_MAGIC;
77	  s.version = HYBRID_STATE_VERSION;
78	  s.flags = HYBRID_FLAG_RV64;
79	  s.pc = pc;
80	  s.priv = 3;
81	  s.gpr[10] = x10;
82	  return s;
83	}
84	
85	auto find_write(const std::vector<DmiOp>& ops, uint8_t reg)
86	  -> std::vector<uint32_t>
87	{
88	  std::vector<uint32_t> values;
89	  for (const auto& op : ops)
90	    if (op.kind == DmiOp::Kind::Write && op.reg == reg)
91	      values.push_back(op.value);
92	  return values;
93	}
94	
95	auto count_writes_to(const std::vector<DmiOp>& ops, uint8_t reg) -> std::size_t
96	{
97	  std::size_t n = 0;
98	  for (const auto& op : ops)
99	    if (op.kind == DmiOp::Kind::Write && op.reg == reg) ++n;
100	  return n;
101	}
102	
103	}  // namespace
104	
105	TEST_CASE("resume halts the hart before any abstract command")
106	{
107	  RecordingBus bus;
108	  // dmstatus answers halted+resumeack so poll loops finish on the first read.
109	  bus.dmstatus_value = (1u << 9) | (1u << 17);
110	
111	  hybrid::ResumeDriver driver(bus);
112	  driver.resume(rv64_state(/*pc=*/0x80001000, /*x10=*/0xdeadbeef));
113	
114	  // The first write must prime dmactive (DM out of reset) BEFORE haltreq is
115	  // accepted; the second write must add haltreq while keeping dmactive set.
116	  REQUIRE(bus.ops.size() >= 2);
117	
118	  const auto& prime = bus.ops[0];
119	  CHECK(prime.kind == DmiOp::Kind::Write);
120	  CHECK(prime.reg == kDmcontrol);
121	  CHECK((prime.value & 1u) == 1u);                  // dmactive
122	  CHECK(((prime.value >> 31) & 1u) == 0u);          // haltreq NOT yet set
123	
124	  const auto& halt = bus.ops[1];
125	  CHECK(halt.kind == DmiOp::Kind::Write);
126	  CHECK(halt.reg == kDmcontrol);
127	  CHECK((halt.value & 1u) == 1u);                   // dmactive still set
128	  CHECK(((halt.value >> 31) & 1u) == 1u);           // haltreq
129	}
