131	TEST_CASE("resume programs x1..x31 via DATA0/DATA1 + COMMAND, skipping x0")
132	{
133	  RecordingBus bus;
134	  bus.dmstatus_value = (1u << 9) | (1u << 17);
135	
136	  auto s = rv64_state(0x80001000, 0xdeadbeef);
137	  for (int i = 0; i < 32; ++i) s.gpr[i] = 0xa00000000ULL + i;
138	
139	  hybrid::ResumeDriver driver(bus);
140	  driver.resume(s);
141	
142	  std::vector<uint32_t> cmds;
143	  for (const auto& op : bus.ops)
144	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
145	      cmds.push_back(op.value);
146	
147	  CHECK(cmds.size() >= 31);
148	
149	  for (int i = 1; i < 32; ++i) {
150	    const auto expect =
151	      hybrid::access_register_command(hybrid::regno_gpr(i),
152	                                      hybrid::AarSize::Bits64, /*write=*/true);
153	    CHECK(cmds[i - 1] == expect);
154	  }
155	
156	  for (const auto& cmd : cmds) {
157	    const uint16_t regno = cmd & 0xffffu;
158	    CHECK(regno != hybrid::regno_gpr(0));
159	  }
160	}
