162	TEST_CASE("resume writes DPC = state.pc")
163	{
164	  RecordingBus bus;
165	  bus.dmstatus_value = (1u << 9) | (1u << 17);
166	
167	  constexpr uint64_t pc = 0x12345678'9ABCDEF0ULL;
168	  hybrid::ResumeDriver driver(bus);
169	  driver.resume(rv64_state(pc, 0));
170	
171	  // Look for the COMMAND write that targets CSR DPC (regno=0x7B1).
172	  std::vector<std::size_t> dpc_cmd_indices;
173	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
174	    const auto& op = bus.ops[i];
175	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
176	        && (op.value & 0xffffu) == kCsrDpc) {
177	      dpc_cmd_indices.push_back(i);
178	    }
179	  }
180	  REQUIRE(dpc_cmd_indices.size() == 1);
181	
182	  // Immediately preceding writes must set DATA0=low32(pc), DATA1=high32(pc).
183	  const auto cmd_idx = dpc_cmd_indices[0];
184	  REQUIRE(cmd_idx >= 2);
185	  const auto& d0 = bus.ops[cmd_idx - 2];
186	  const auto& d1 = bus.ops[cmd_idx - 1];
187	  CHECK(d0.kind == DmiOp::Kind::Write);
188	  CHECK(d0.reg == kData0);
189	  CHECK(d0.value == uint32_t(pc & 0xffffffffu));
190	  CHECK(d1.kind == DmiOp::Kind::Write);
191	  CHECK(d1.reg == kData1);
192	  CHECK(d1.value == uint32_t((pc >> 32) & 0xffffffffu));
193	}
