195	TEST_CASE("resume issues resumereq after register programming")
196	{
197	  RecordingBus bus;
198	  bus.dmstatus_value = (1u << 9) | (1u << 17);
199	
200	  hybrid::ResumeDriver driver(bus);
201	  driver.resume(rv64_state(0x80001000, 0));
202	
203	  // The last DMCONTROL write must clear haltreq and set resumereq.
204	  const auto dmctl_writes = find_write(bus.ops, kDmcontrol);
205	  REQUIRE(dmctl_writes.size() >= 2);
206	  const auto last = dmctl_writes.back();
207	  CHECK((last & 1u) == 1u);                  // dmactive still on
208	  CHECK(((last >> 31) & 1u) == 0u);          // haltreq cleared
209	  CHECK(((last >> 30) & 1u) == 1u);          // resumereq set
210	}
