248	TEST_CASE("resume issues exactly one COMMAND per programmed register")
249	{
250	  RecordingBus bus;
251	  bus.dmstatus_value = (1u << 9) | (1u << 17);
252	
253	  hybrid::ResumeDriver driver(bus);
254	  driver.resume(rv64_state(0x80001000, 0));
255	
256	  // x1..x31 + DPC at minimum (x0 skipped). We do not yet program FPR/CSR/V.
257	  CHECK(count_writes_to(bus.ops, kCommand) >= 32u);
258	}
