260	namespace {
261	
262	auto cmd_regnos(const std::vector<DmiOp>& ops) -> std::vector<uint16_t>
263	{
264	  std::vector<uint16_t> ns;
265	  for (const auto& op : ops)
266	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
267	      ns.push_back(static_cast<uint16_t>(op.value & 0xffffu));
268	  return ns;
269	}
270	
271	auto contains_regno(const std::vector<uint16_t>& ns, uint16_t regno) -> bool
272	{
273	  for (auto n : ns) if (n == regno) return true;
274	  return false;
275	}
276	
277	}  // namespace
