279	TEST_CASE("resume does NOT program M-mode CSRs/PMP via DM Abstract Commands; "
280	          "those fields are pass-through-merged at drain time instead")
281	{
282	  RecordingBus bus;
283	  bus.dmstatus_value = (1u << 9) | (1u << 17);
284	
285	  auto s = rv64_state(0x80001000, 0);
286	  s.mstatus = 0x1800ULL;
287	  for (int i = 0; i < HYBRID_PMP_CFG_NUM; ++i)  s.pmpcfg[i]  = 0xa0 + i;
288	  for (int i = 0; i < HYBRID_PMP_ADDR_NUM; ++i) s.pmpaddr[i] = 0xb0 + i;
289	
290	  hybrid::ResumeDriver driver(bus);
291	  driver.resume(s);
292	
293	  const auto ns = cmd_regnos(bus.ops);
294	  for (uint16_t csr : {0x300, 0x341, 0x342, 0x343, 0x340,
295	                       0x302, 0x303, 0x344, 0x304, 0xb00, 0xb02, 0x180})
296	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(csr)));
297	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
298	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(0x3a0 + i)));
299	}
