301	TEST_CASE("resume with HYBRID_FLAG_FP programs f0..f31 via Abstract Commands")
302	{
303	  RecordingBus bus;
304	  bus.dmstatus_value = (1u << 9) | (1u << 17);
305	
306	  auto s = rv64_state(0x80001000, 0);
307	  s.flags  |= HYBRID_FLAG_FP;
308	  s.mstatus = 0x6000ULL;  // mstatus.FS = Dirty: FPRs are writable
309	  for (int i = 0; i < 32; ++i) s.fpr[i] = 0xf000000000000000ULL + i;
310	
311	  hybrid::ResumeDriver driver(bus);
312	  driver.resume(s);
313	
314	  const auto ns = cmd_regnos(bus.ops);
315	  for (uint16_t i = 0; i < 32; ++i)
316	    CHECK(contains_regno(ns, hybrid::regno_fpr(i)));
317	}
