319	TEST_CASE("resume with HYBRID_FLAG_FP: mstatus written before FPR Abstract Commands")
320	{
321	  RecordingBus bus;
322	  bus.dmstatus_value = (1u << 9) | (1u << 17);
323	
324	  auto s = rv64_state(0x80001000, 0);
325	  s.flags  |= HYBRID_FLAG_FP;
326	  s.mstatus = 0x6000ULL;
327	  s.fpr[0]  = 0xdeadbeefcafef00dULL;
328	
329	  hybrid::ResumeDriver driver(bus);
330	  driver.resume(s);
331	
332	  std::optional<std::size_t> mstatus_cmd_idx;
333	  std::optional<std::size_t> f0_cmd_idx;
334	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
335	    const auto& op = bus.ops[i];
336	    if (op.kind != DmiOp::Kind::Write || op.reg != kCommand) continue;
337	    const auto regno = static_cast<uint16_t>(op.value & 0xFFFFu);
338	    if (!mstatus_cmd_idx && regno == hybrid::regno_csr(0x300))
339	      mstatus_cmd_idx = i;
340	    if (!f0_cmd_idx && regno == hybrid::regno_fpr(0))
341	      f0_cmd_idx = i;
342	  }
343	  REQUIRE(mstatus_cmd_idx.has_value());
344	  REQUIRE(f0_cmd_idx.has_value());
345	  CHECK(*mstatus_cmd_idx < *f0_cmd_idx);
346	}
