348	TEST_CASE("resume with HYBRID_FLAG_FP: FPR writes carry the state value via DATA0/DATA1")
349	{
350	  RecordingBus bus;
351	  bus.dmstatus_value = (1u << 9) | (1u << 17);
352	
353	  auto s = rv64_state(0x80001000, 0);
354	  s.flags  |= HYBRID_FLAG_FP;
355	  s.mstatus = 0x6000ULL;
356	  s.fpr[7]  = 0x0123456789ABCDEFULL;
357	
358	  hybrid::ResumeDriver driver(bus);
359	  driver.resume(s);
360	
361	  std::optional<std::size_t> f7_cmd_idx;
362	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
363	    const auto& op = bus.ops[i];
364	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
365	        && (op.value & 0xFFFFu) == hybrid::regno_fpr(7)) {
366	      f7_cmd_idx = i;
367	      break;
368	    }
369	  }
370	  REQUIRE(f7_cmd_idx.has_value());
371	  REQUIRE(*f7_cmd_idx >= 2);
372	  const auto& d0 = bus.ops[*f7_cmd_idx - 2];
373	  const auto& d1 = bus.ops[*f7_cmd_idx - 1];
374	  CHECK(d0.kind == DmiOp::Kind::Write);
375	  CHECK(d0.reg == kData0);
376	  CHECK(d0.value == uint32_t(s.fpr[7] & 0xFFFFFFFFu));
377	  CHECK(d1.kind == DmiOp::Kind::Write);
378	  CHECK(d1.reg == kData1);
379	  CHECK(d1.value == uint32_t(s.fpr[7] >> 32));
380	}
