398	TEST_CASE("resume with HYBRID_FLAG_V restores vstart/vxsat/vxrm/vcsr via abstract commands")
399	{
400	  RecordingBus bus;
401	  bus.dmstatus_value = (1u << 9) | (1u << 17);
402	
403	  auto s = rv64_state(0x80001000, 0);
404	  s.flags |= HYBRID_FLAG_V;
405	  s.vstart = 4;
406	  s.vxsat  = 1;
407	  s.vxrm   = 2;
