413	  const auto ns = cmd_regnos(bus.ops);
414	  CHECK(contains_regno(ns, hybrid::regno_csr(0x008)));  // vstart
415	  CHECK(contains_regno(ns, hybrid::regno_csr(0x009)));  // vxsat
416	  CHECK(contains_regno(ns, hybrid::regno_csr(0x00A)));  // vxrm
417	  CHECK(contains_regno(ns, hybrid::regno_csr(0x00F)));  // vcsr
