420	TEST_CASE("resume with HYBRID_FLAG_V: V CSR abstract writes precede GPR writes")
421	{
422	  RecordingBus bus;
423	  bus.dmstatus_value = (1u << 9) | (1u << 17);
424	
425	  auto s = rv64_state(0x80001000, 0);
426	  s.flags  |= HYBRID_FLAG_V;
427	  s.vstart = 1;
428	
429	  hybrid::ResumeDriver driver(bus);
430	  driver.resume(s);
431	
432	  // x5/x6 are written as scratch for vsetvl inside the V block, so look for
433	  // x1 specifically -- it is always the first register in the GPR restore loop.
434	  std::optional<std::size_t> vstart_cmd_idx;
435	  std::optional<std::size_t> x1_restore_cmd_idx;
436	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
437	    const auto& op = bus.ops[i];
438	    if (op.kind != DmiOp::Kind::Write || op.reg != kCommand) continue;
439	    const auto regno = static_cast<uint16_t>(op.value & 0xFFFFu);
440	    if (!vstart_cmd_idx && regno == hybrid::regno_csr(0x008))
441	      vstart_cmd_idx = i;
442	    if (!x1_restore_cmd_idx && regno == hybrid::regno_gpr(1))
443	      x1_restore_cmd_idx = i;
444	  }
445	  REQUIRE(vstart_cmd_idx.has_value());
446	  REQUIRE(x1_restore_cmd_idx.has_value());
447	  CHECK(*vstart_cmd_idx < *x1_restore_cmd_idx);
448	}
