450	TEST_CASE("resume with HYBRID_FLAG_V: PB fallback when abstract vstart write fails")
451	{
452	  RecordingBus bus;
453	  bus.dmstatus_value = (1u << 9) | (1u << 17);
454	
455	  auto s = rv64_state(0x80001000, 0);
456	  s.flags  |= HYBRID_FLAG_V;
457	  s.vstart = 42;
458	  // mstatus.VS == 0 so mstatus write is skipped.
459	  // With Tier-B, abstractcs reads before vstart's cmderr check:
460	  //   [1] x5 busy-poll, [2] x6 busy-poll,
461	  //   [3] exec_progbuf pre-cmderr, [4] exec_progbuf busy-poll,
462	  //   [5] exec_progbuf post-cmderr, [6] vstart abstract-write busy-poll,
463	  //   [7] vstart cmderr check <- kCmderr triggers PB fallback.
464	  constexpr uint32_t kCmderr = 0x7u << 8;
465	  bus.abstractcs_queue = {0u, 0u, 0u, 0u, 0u, 0u, kCmderr};
466	
467	  hybrid::ResumeDriver driver(bus);
468	  driver.resume(s);
469	
470	  // csrrw x0, vstart(0x008), x5 -- stage value in t0(x5), write to vstart via PB
471	  const uint32_t expected_pb0 = hybrid::encode_csrrw(0, 0x008, 5);
472	  bool found_pb0 = false;
473	  bool found_exec = false;
474	  for (const auto& op : bus.ops) {
475	    if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
476	        && op.value == expected_pb0)
477	      found_pb0 = true;
478	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
479	        && op.value == hybrid::kExecProgbufCmd)
480	      found_exec = true;
481	  }
482	  CHECK(found_pb0);
483	  CHECK(found_exec);
484	}
