486	TEST_CASE("resume with HYBRID_FLAG_V: vsetvl PB fires with vl in x5, vtype in x6")
487	{
488	  RecordingBus bus;
489	  bus.dmstatus_value = (1u << 9) | (1u << 17);
490	
491	  auto s = rv64_state(0x80001000, 0);
492	  s.flags |= HYBRID_FLAG_V;
493	  s.vl    = 16;
494	  s.vtype = 0xC1;  // LMUL=1, SEW=64
495	
496	  hybrid::ResumeDriver driver(bus);
497	  driver.resume(s);
498	
499	  // Expect: write x5=vl, write x6=vtype, then exec vsetvl x0,x5,x6 in PB.
500	  const uint32_t expected_vsetvl = hybrid::encode_vsetvl(0, 5, 6);
501	  bool found_x5_vl    = false;
502	  bool found_x6_vtype = false;
503	  bool found_vsetvl   = false;
504	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
505	    const auto& op = bus.ops[i];
506	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand) {
507	      const uint16_t regno = static_cast<uint16_t>(op.value & 0xFFFFu);
508	      if (regno == hybrid::regno_gpr(5) && i >= 2) {
509	        const auto& d0 = bus.ops[i - 2];
510	        const auto& d1 = bus.ops[i - 1];
511	        if (d0.reg == kData0 && d0.value == uint32_t(s.vl & 0xFFFFFFFFu) &&
512	            d1.reg == kData1 && d1.value == uint32_t(s.vl >> 32))
513	          found_x5_vl = true;
514	      }
515	      if (regno == hybrid::regno_gpr(6) && i >= 2) {
516	        const auto& d0 = bus.ops[i - 2];
517	        const auto& d1 = bus.ops[i - 1];
518	        if (d0.reg == kData0 && d0.value == uint32_t(s.vtype & 0xFFFFFFFFu) &&
519	            d1.reg == kData1 && d1.value == uint32_t(s.vtype >> 32))
520	          found_x6_vtype = true;
521	      }
522	    }
523	    if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
524	        && op.value == expected_vsetvl)
525	      found_vsetvl = true;
526	  }
