16	// ---- Recording DmiBus stub -------------------------------------------------
17	// Captures all writes; returns configurable values per register address.
18	struct RecBus
19	{
20	    struct Op { uint8_t reg; uint32_t val; };
21	
22	    std::vector<Op> writes;
23	    // Per-register read sequences: each call pops the front value.
24	    // If the list is empty, returns 0.
25	    std::map<uint8_t, std::vector<uint32_t>> read_seq;
26	
27	    void write(uint8_t reg, uint32_t val) { writes.push_back({reg, val}); }
28	
29	    uint32_t read(uint8_t reg)
30	    {
31	        auto it = read_seq.find(reg);
32	        if (it == read_seq.end() || it->second.empty()) return 0u;
33	        uint32_t v = it->second.front();
34	        it->second.erase(it->second.begin());
35	        return v;
36	    }
37	};
