1	// Recording DmiBus mock shared by the StateDrain, HandoffController, and
2	// ResumeDriver tests. Captures the (op, reg, value) sequence and latches
3	// abstract-command read responses so test fixtures can pre-program a
4	// regfile and assert on the resulting DMI traffic.
5	
6	#pragma once
7	
8	#include "hybrid/resume_driver.hpp"
9	
10	#include <cstdint>
11	#include <unordered_map>
12	#include <vector>
13	
14	namespace hybrid::test
15	{
16	
17	struct DmiOp
18	{
19	  enum class Kind
20	  {
21	    Write,
22	    Read,
23	  };
24	  Kind kind;
25	  uint8_t reg;
26	  uint32_t value;
27	};
28	
29	struct RecordingBus final : hybrid::DmiBus
30	{
31	  std::vector<DmiOp> ops;
32	
33	  // Test-controlled response values for the polled status registers.
34	  uint32_t dmstatus_value   = 0;
35	  uint32_t abstractcs_value = 0;
36	
37	  // For abstract-command reads: maps DM regno -> 64-bit value. When the
38	  // driver writes COMMAND with read=true, we latch the matching regfile
39	  // entry into pending_data{0,1} so the next DATA0/DATA1 reads return it.
40	  std::unordered_map<uint16_t, uint64_t> regfile;
41	
42	  uint32_t pending_data0 = 0;
43	  uint32_t pending_data1 = 0;
44	
45	  void write(uint8_t reg, uint32_t value) override
46	  {
47	    ops.push_back({DmiOp::Kind::Write, reg, value});
48	    if (reg == hybrid::ResumeDriver::kCommand) {
49	      const uint16_t regno = value & 0xffffu;
50	      const bool is_write  = ((value >> 16) & 1u) != 0;
51	      if (!is_write) {
52	        const auto it = regfile.find(regno);
53	        const uint64_t v = (it == regfile.end()) ? 0 : it->second;
54	        pending_data0 = static_cast<uint32_t>(v & 0xffffffffu);
55	        pending_data1 = static_cast<uint32_t>((v >> 32) & 0xffffffffu);
56	      }
57	    }
58	  }
59	
60	  auto read(uint8_t reg) -> uint32_t override
61	  {
62	    ops.push_back({DmiOp::Kind::Read, reg, 0});
63	    if (reg == hybrid::ResumeDriver::kDmstatus)   return dmstatus_value;
64	    if (reg == hybrid::ResumeDriver::kAbstractcs) return abstractcs_value;
65	    if (reg == hybrid::ResumeDriver::kData0)      return pending_data0;
66	    if (reg == hybrid::ResumeDriver::kData1)      return pending_data1;
67	    return 0;
68	  }
69	};
