    }
    if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
        && op.value == expected_vsetvl)
      found_vsetvl = true;
  }
  CHECK(found_x5_vl);
  CHECK(found_vsetvl);
}
```
The pattern: (1) encode the instruction with `encode_vsetvl()`, (2) scan `bus.ops` for writes to `kProgbuf0` (DMI register 0x20), (3) verify the encoded value matches, (4) separately verify x5/x6 DATA0/DATA1 writes precede the progbuf0 write.

